INSERT INTO public.photos VALUES (24321, 'Santa Engracia c.1930', 'Imagen centrada en una vista parcial de la fachada de la iglesia de Santa Engracia, que permite un breve vistazo, a la izquierda, en la calle Don Hernando de Aragâ”śâ”‚n, al convento y casa de las Religiosas de Marâ”śÂˇa Inmaculada, realizado con proyecto de Federico Arias Rey en 1913, y con acceso desde el paseo de la Mina. Las titulares perduran en esa ubicaciâ”śâ”‚n (luego, avenida de Marina Moreno), aunque en un edificio distinto, mâ”śĂ­s moderno, ya en tiempos del paseo de la Constituciâ”śâ”‚n. Fuente visual: Foto Estudio Coyne, AHPZ.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.64916800, -0.88288700, '0101000020E61000009E08E23C9C40ECBF0CCEE0EF17D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31524126312.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31524126312.webp', 'https://www.flickr.com/photos/zaragozaantigua/31524126312/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24326, 'Baptisterio siglo IV', 'Foto: Oliver Duch. Durante las excavaciones arqueolâ”śâ”‚gicas de 2008 que buscaban encontrar el primitivo pozo martirial de Santa Engracia (sin resultado), se hallaron los restos de un baptisterio del siglo IV. Se trata del vestigio arquitectâ”śâ”‚nico mâ”śĂ­s antiguo del cristianismo encontrado en Zaragoza. En la foto, el yacimiento, a los pies de las escaleras que llevan a la cripta, en la iglesia de Santa Engracia. Fuente: Heraldo de Aragâ”śâ”‚n.', 350, 300, 399, 'Siglo XIX', 'CENTRO', 41.64889400, -0.88286700, '0101000020E6100000D7F6764B7240ECBF0A4966F50ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32835734406.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32835734406.webp', 'https://www.flickr.com/photos/zaragozaantigua/32835734406/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24327, 'Imperio Argentina 1998', 'La actriz Magdalena Nile del Râ”śÂˇo, conocida como Imperio Argentina (1910-2003), saluda en la puerta del Gran Hotel en 1998. Habâ”śÂˇa sido pregonera de las fiestas en 1996. Fuente: Heraldo de Aragâ”śâ”‚n.', 1998, 1998, 1998, 'Anos 90', 'CENTRO', 41.64898400, -0.88166400, '0101000020E6100000FAEFC16B9736ECBF4AD05FE811D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33119272181.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33119272181.webp', 'https://www.flickr.com/photos/zaragozaantigua/33119272181/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24333, 'Gran Hotel 1928', 'Acciâ”śâ”‚n emitida en 1928 por la empresa Gran Hotel Zaragoza S A, cuyo presidente era Manuel de Escoriaza y Fabro. El establecimiento serâ”śÂˇa inaugurado en 1929, en el marco de la urbanizaciâ”śâ”‚n de la Huerta de Santa Engracia posterior a la Exposiciâ”śâ”‚n Hispano-Francesa de 1908. El dibujo del edificio lo muestra desde la calle de Isaac Peral, con la entrada principal a la derecha, esquinera con la calle de Joaquâ”śÂˇn Costa. Fuente: www.todocoleccion.net', 1928, 1928, 1928, 'Anos 20', 'CENTRO', 41.64917400, -0.88148100, '0101000020E6100000B87361A41735ECBFEEB4352218D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39086135311.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39086135311.webp', 'https://www.flickr.com/photos/zaragozaantigua/39086135311/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24336, 'Plaza de Santa Engracia c.1927', 'Imagen centrada en la portada de la iglesia parroquial de Santa Engracia sita en la homâ”śâ”‚nima plaza. A la izquierda, la calle de Don Hernando de Aragâ”śâ”‚n, donde destaca el solar del nâ”¬â•‘ 2 de la calle de Joaquâ”śÂˇn Costa, previo a la construcciâ”śâ”‚n del inmueble diseâ”śâ–’ado por Francisco Albiâ”śâ–’ana para albergar la sede del periâ”śâ”‚dico La Voz de Aragâ”śâ”‚n. Detrâ”śĂ­s, medianera del convento de las Religiosas de Marâ”śÂˇa Inmaculada, con ingreso principal por el paseo de la Mina. A la derecha, entrada a la calle de Tomâ”śĂ­s Castellano.', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.64909800, -0.88283300, '0101000020E6100000D28BDAFD2A40ECBF13F3ACA415D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49923195407.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49923195407.webp', 'https://www.flickr.com/photos/zaragozaantigua/49923195407/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24338, 'Exposiciâ”śâ”‚n 1908', 'Imagen de la Exposiciâ”śâ”‚n Hispano-Francesa de 1908 centrada en la gran avenida central que con orientaciâ”śâ”‚n este-oeste estaba delimitada entre los pabellones de Tracciâ”śâ”‚n y de Mâ”śĂ­quinas, y las instalaciones especiales del Acumulador Tudor y de las Destilerâ”śÂˇas Benedictinas, a la izquierda, y el pabellâ”śâ”‚n central de Alimentaciâ”śâ”‚n, a la derecha y fuera de plano. La multitud de sillas de primer tâ”śÂ®rmino estaban dispuestas para descanso de visitantes, y la avenida desemboca hacia la derecha en la plaza central donde destaca el Quiosco de la Mâ”śâ•‘sica, y tras â”śÂ®l el Pabellâ”śâ”‚n Francâ”śÂ®s. Fuera del recinto emerge al fondo la iglesia de Santa Engracia.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64844800, -0.87992500, '0101000020E61000007FD93D795828ECBF0C94145800D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50023010682.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50023010682.webp', 'https://www.flickr.com/photos/zaragozaantigua/50023010682/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24507, 'Pâ”¬â•‘ Independencia c.1955', 'Fachada de la tienda que la empresa de muebles y artes decorativas Simâ”śâ”‚n Loscertales Bona mantenâ”śÂˇa en el paseo de la Independencia nâ”¬â•‘ 34 desde el comienzo de la dâ”śÂ®cada de los aâ”śâ–’os 50, en los bajos del "Edificio Ambos Mundos", asâ”śÂˇ denominado por la imponente presencia (a la derecha, fuera de plano) del Gran Cafâ”śÂ® Ambos Mundos, abierto en 1881, y cerrado en septiembre de 1955. Al fondo, la calle de Albareda, con vista parcial del antiguo y desaparecido hotelito correspondiente al nâ”¬â•‘ 13 de la plaza de Aragâ”śâ”‚n. En la inmediata parte trasera del edificio "Ambos Mundos", recayente a la calle de Ponzano, estaba emplazado un cuartel de la Policâ”śÂˇa Armada. Fuente visual: Archivo familiar Simâ”śâ”‚n Loscertales Bona, en la exposiciâ”śâ”‚n "Simâ”śâ”‚n Loscertales Bona. Una firma emblemâ”śĂ­tica", Centro de Historias de Zaragoza. Del 2 de febrero al 2 de abril de 2017.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64922000, -0.88437600, '0101000020E6100000E4C0ABE5CE4CECBF5EF415A419D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31992764283.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31992764283.webp', 'https://www.flickr.com/photos/zaragozaantigua/31992764283/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25106, 'Plaza de Aragâ”śâ”‚n 1929', 'Imagen capturada en el ingreso al hotelito del nâ”¬â•‘ 1 de la plaza de Aragâ”śâ”‚n donde estaba residenciado el Gobierno civil, con un posado colectivo durante uno de los actos organizados por los Ayuntamientos de la provincia, la Diputaciâ”śâ”‚n provincial, el partido polâ”śÂˇtico Uniâ”śâ”‚n Patriâ”śâ”‚tica y el Cuerpo de secretarios municipales, en homenaje al gobernador civil de la provincia, general Juan Cantâ”śâ”‚n Salazar con motivo del segundo aniversario de su designaciâ”śâ”‚n para tal cargo, el 16 de mayo de 1927, por la dictadura de Primo de Rivera. En la imagen, posado colectivo de una representaciâ”śâ”‚n de los Ayuntamientos de la provincia donde destaca en primer tâ”śÂ®rmino el alcalde de Zaragoza, Miguel Alluâ”śÂ® Salvador, a la derecha de un artâ”śÂˇstico â”śĂ­lbum contenedor de las firmas de los alcaldes de todos los pueblos de la provincia, y tras â”śÂ®l el presidente de la Diputaciâ”śâ”‚n provincial, Patricio Borobio Dâ”śÂˇez. El homenajeado figura a la izquierda del â”śĂ­lbum. Como no podâ”śÂˇa ser de otra forma, el acto se convirtiâ”śâ”‚ en una manifestaciâ”śâ”‚n de adhesiâ”śâ”‚n al gobernador civil, al Rey y al Gobierno.', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.64866500, -0.88405600, '0101000020E610000076A4FACE2F4AECBFA987687407D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52441458110.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52441458110.webp', 'https://www.flickr.com/photos/zaragozaantigua/52441458110/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25282, 'Boda de los Foranos 1916', 'El periâ”śâ”‚dico Heraldo de Aragâ”śâ”‚n publicâ”śâ”‚ en su ediciâ”śâ”‚n del 12 de octubre de 1916 una noticia con fotografâ”śÂˇa muy propia de la Zaragoza del siglo XIX... XX, acerca de la celebraciâ”śâ”‚n de la boda de dos de los "cabezudos" de la comparsa de Zaragoza: la Forana y el Forano, con el titular de "Los Foranos reciâ”śÂ®n casados y su comitiva nupcial". En la imagen la calesa en la que viajan los dos moâ”śâ–’acos tras sus imaginarias nupcias, son paseados por la ciudad, ahora saliendo de la calle de Juan Bruil y entrando en la de Independencia, para acercarse al Hotel Oriente, en el Coso 11-13, a que coman los humanos que hay debajo de los cabezudos. El edificio de la esquina de los porches se corresponde con el nâ”¬â•‘ 37 del paseo, realizado en eclâ”śÂ®ctico estilo radicalmente "reformado" en el aâ”śâ–’o 1952, cuando se instale en sus bajos la sede de una entidad local bancaria.', 1916, 1916, 1916, 'Anos 10', 'CENTRO', 41.64882000, -0.88410200, '0101000020E61000008D800A47904AECBFD07EA4880CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15273868718.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15273868718.webp', 'https://www.flickr.com/photos/zaragozaantigua/15273868718/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25290, 'Remolacheros 1914', 'Manifestaciâ”śâ”‚n en el paseo de la Independencia, frente al Gobierno Civil (plaza de Aragâ”śâ”‚n 1), reivindicando la apertura del ferrocarril de Canfranc por parte de los remolacheros zaragozanos. Aâ”śâ•‘n quedaban otros 14 aâ”śâ–’os para la inauguraciâ”śâ”‚n.', 1914, 1914, 1914, 'Anos 10', 'CENTRO', 41.64882000, -0.88410200, '0101000020E61000008D800A47904AECBFD07EA4880CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15717513868.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15717513868.webp', 'https://www.flickr.com/photos/zaragozaantigua/15717513868/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25292, 'Antiguo Hotel Regina 1936', 'AHPZ. Manuel Coyne Buil. 1936. "Grupo de gente de Acciâ”śâ”‚n Ciudadana con otros paisanos junto a un camiâ”śâ”‚n de suministros a las tropas procedente del barrio de Casetas." Imagen capturada en la calle Bruil, ante la fachada del antiguo Hotel Regina, que desde 1919 venâ”śÂˇa siendo utilizado como local de una Academia Preparatoria militar. Improvisado "castellet" de facciosos nacionalistas de la ciudad y la periferia, tras el fallido golpe de Estado de julio de 1936.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64854400, -0.88349800, '0101000020E6100000E59A02999D45ECBF2E02637D03D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15921436161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15921436161.webp', 'https://www.flickr.com/photos/zaragozaantigua/15921436161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25318, 'P.â”¬â•‘ de la Independencia 1928', 'Paseo de la Independencia. A la izquierda, la calle de Albareda. En el centro del bulevar, el cenotafio "A los funcionarios muertos en agosto de 1920", en esa ubicaciâ”śâ”‚n hasta 1961. Fuente visual: Foto Conrado Barlâ”śÂ®s, donada por Daniel Barlâ”śÂ®s y digitalizada por Josâ”śÂ® Luis Cintora para www.rafaelcastillejo.com', 1928, 1928, 1928, 'Anos 20', 'CENTRO', 41.64899200, -0.88430300, '0101000020E6100000672618CE354CECBFCDAE7B2B12D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23245809555.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23245809555.webp', 'https://www.flickr.com/photos/zaragozaantigua/23245809555/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25327, '8 de marzo de 1936', 'Arenga feminista frente al Gobierno Civil cuando â”śÂ®ste se ubicaba en el nâ”¬â•‘ 1 de la plaza de Aragâ”śâ”‚n, durante la manifestaciâ”śâ”‚n de la Jornada Internacional de la Mujer, convocada por las organizaciones de la izquierda frentepopulista zaragozana el 8 de marzo de 1936, que con gran afluencia de pâ”śâ•‘blico, se convirtiâ”śâ”‚ de facto en el primer "8 de marzo" celebrado en la ciudad como Dâ”śÂˇa Internacional de la Mujer y â”śâ•‘ltimo hasta finales de los aâ”śâ–’os 70. Tras la sublevaciâ”śâ”‚n monâ”śĂ­rquica, militar y fascista respaldada por el râ”śÂ®gimen de Mussolini en julio de ese mismo aâ”śâ–’o y durante muchas dâ”śÂ®cadas, la presencia de la mujer en puestos destacados en la sociedad civil fue reducida a algunos elementos cosmâ”śÂ®ticos. En la imagen, Josefina Lâ”śâ”‚pez, de las Juventudes Comunistas, en uno de los mâ”śÂˇtines al pâ”śâ•‘blico asistente. Al fondo y a la derecha, calle de Josâ”śÂ® Luis Albareda en su confluencia con el paseo de la Independencia, con detalle de la fachada del esquinero "hotelito" del nâ”¬â•‘ 13 de la plaza de Aragâ”śâ”‚n.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64894400, -0.88429300, '0101000020E6100000849D62D5204CECBFBC77D49810D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24102074002.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24102074002.webp', 'https://www.flickr.com/photos/zaragozaantigua/24102074002/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25351, 'Vista aâ”śÂ®rea Independencia c.1968', 'Vista aâ”śÂ®rea del paseo de la Independencia. Abajo, avenida de Calvo Sotelo. Arriba, plaza de Espaâ”śâ–’a. Fuente visual: foto Pedro Marco.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.64901900, -0.88433900, '0101000020E61000009A79724D814CECBFC7BDF90D13D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33313932290.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33313932290.webp', 'https://www.flickr.com/photos/zaragozaantigua/33313932290/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25518, 'Arco Triunfal 1903', 'Imagen del primero de los tres arcos triunfales construidos en la calle de la Independencia, con motivo de la visita del rey Alfonso XIII durante las fiestas del Pilar del aâ”śâ–’o 1903. Esta muestra de arquitectura efâ”śÂˇmera y festiva fue costeada por la Quinta Regiâ”śâ”‚n Militar del ejâ”śÂ®rcito, realizâ”śĂ­ndose en las instalaciones de Pontoneros con diseâ”śâ–’o de dos capitanes del cuerpo de ingenieros, y otro del de artillerâ”śÂˇa. El resultado final fue un liviano portal ornado con motivos castrenses varios, y un estilo muy en lâ”śÂˇnea con el "art nouveau" entonces en moda. Este arco fue instalado en las inmediaciones de la glorieta de Pignatelli, entre el cafâ”śÂ® "Ambos Mundos", a la izquierda, y el teatro Pignatelli, a la derecha. Al fondo, el segundo de los arcos triunfales construidos para la ocasiâ”śâ”‚n: el costeado por el Ayuntamiento, con diseâ”śâ–’o de Ricardo Magdalena, levantado a la altura de la calle Zurita. Mâ”śĂ­s al fondo, ya casi en la plaza de la Constituciâ”śâ”‚n, fue instalado el tercero y â”śâ•‘ltimo de los arcos, de la Maestranza. Fuente visual: www.todocoleccion.net/', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.64918800, -0.88402200, '0101000020E610000071395E81E849ECBF537AA69718D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27757280490.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27757280490.webp', 'https://www.flickr.com/photos/zaragozaantigua/27757280490/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25858, 'Teatro Pignatelli 1889', '"Saragosse. Thâ”śÂ®â”śĂłtre de Pignatelli et Promenade de Sta. Engracia". J. Lâ”śÂ®vy et Cie, 1889. Agence Roger-Viollet, Parâ”śÂˇs. Fuente: Zaragoza en la memoria ajena.', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.64921800, -0.88363400, '0101000020E6100000FA4674CFBA46ECBFBDFC4E9319D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14701173560.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14701173560.webp', 'https://www.flickr.com/photos/zaragozaantigua/14701173560/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25859, 'Teatro Pignatelli 1878', 'Fondo Documental Histâ”śâ”‚rico de las Cortes de Aragâ”śâ”‚n. 1878. Zaragoza: exterior del "Teatro de Pignatelli", construido en la calle de la Independencia bajo la direcciâ”śâ”‚n del arquitecto Fâ”śÂ®lix Navarro.', 1878, 1878, 1878, 'Siglo XIX', 'CENTRO', 41.64892100, -0.88367500, '0101000020E61000009E5E29CB1047ECBF0458E4D70FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14854429926.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14854429926.webp', 'https://www.flickr.com/photos/zaragozaantigua/14854429926/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25904, 'Glorieta de Pignatelli 1902', 'Un tranvâ”śÂˇa de San Sebastiâ”śĂ­n que fue desplazado a Zaragoza para la inauguraciâ”śâ”‚n de la electrificaciâ”śâ”‚n del tranvâ”śÂˇa de Torrero llega a la glorieta de Pignatelli (hoy plaza de Aragâ”śâ”‚n) en 1902. Al fondo, edificio anexo al de Capitanâ”śÂˇa (fuera de plano). Fuente: www.facebook.com/photo.php?fbid=1656961051213358&set=...', 1902, 1902, 1902, 'Anos 1900', 'CENTRO', 41.64899200, -0.88430300, '0101000020E6100000672618CE354CECBFCDAE7B2B12D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21295133555.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21295133555.webp', 'https://www.flickr.com/photos/zaragozaantigua/21295133555/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25923, 'Plaza de Aragâ”śâ”‚n 1968', 'Imagen centrada en la trolebusera unidad nâ”¬â•‘ 51 (adquirida a la British Union Transport) en servicio en la lâ”śÂˇnea "Ciudad Jardâ”śÂˇn", camino de la terminal de la plaza de Santa Engracia. La captura se ha realizado entre la plaza de Aragâ”śâ”‚n, y el desemboque en ella del paseo de la Independencia. Tras el trolebus, la mutante manzana entre las calles Juan Bruil y Agustina Simâ”śâ”‚n, con el obraje del moderno bloque nâ”¬â•‘ 4 de Juan Bruil, levantado donde estuviera el antiguo hotel Regina. El que fuera hotelito sede del antiguo y derribado Gobierno Civil, ahora era solar del que ya emergen pilares encofrados que soportarâ”śĂ­n el nuevo nâ”¬â•‘ 1 de la plaza de Aragâ”śâ”‚n. A la derecha, imagen del hotelito del nâ”¬â•‘ 2 de la plaza, sustituido mâ”śĂ­s tarde por otra colmena moderna.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.64896300, -0.88411900, '0101000020E61000000FB6D8EDB34AECBF33A8363811D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33369244030.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33369244030.webp', 'https://www.flickr.com/photos/zaragozaantigua/33369244030/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
