INSERT INTO public.photos VALUES (21193, 'Calle de Puigcerdâ”śĂ­ 1893', 'Impagable imagen de un coche de caballos descubierto y estacionado en la calle de Puigcerdâ”śĂ­ ante los talleres de la Sociedad Bastos y Laguna, formada por los industriales Atilano Bastos y Amado Laguna de Rins, y constructora de instrumentos de precisiâ”śâ”‚n, matemâ”śĂ­ticos, topogrâ”śĂ­ficos y geodâ”śÂ®sicos desde 1883. En esta ubicaciâ”śâ”‚n, sita en el hotelito del nâ”¬â•‘ 5 de la plaza de Aragâ”śâ”‚n donde residâ”śÂˇa Atilano, antes estuvieron los talleres de Bastos y Compaâ”śâ–’â”śÂˇa, y pocos aâ”śâ–’os despuâ”śÂ®s y tras la adquisiciâ”śâ”‚n por parte de Laguna de Rins de la parte de la sociedad de Bastos, esta empresa se trasladarâ”śÂˇa al camino de los Cubos, al terreno ocupado por la Torre de Laguna, desarrollando una exitosa carrera empresarial. A la izquierda, muro de cierre de la calle tras el que fluâ”śÂˇa al aire el râ”śÂˇo Huerva. Por encima sobresale el gran colegio del Salvador, al otro lado del râ”śÂˇo.', 1893, 1893, 1893, 'Siglo XIX', 'CENTRO', 41.64798300, -0.88417400, '0101000020E6100000F226BF45274BECBF97AE601BF1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50130741077.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50130741077.webp', 'https://www.flickr.com/photos/zaragozaantigua/50130741077/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21206, 'Exposiciâ”śâ”‚n 1908', 'AHPZ. Archivo Coyne. 1908. Exposiciâ”śâ”‚n Hispano-Francesa de 1908. Monumental puerta de acceso principal, situada en el antiguo paseo de la Mina, donde hoy confluyen las calles de Mariano Escar con paseo de la Constituciâ”śâ”‚n.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64787900, -0.88053700, '0101000020E6100000DD5F3DEE5B2DECBFF261F6B2EDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14834912587.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14834912587.webp', 'https://www.flickr.com/photos/zaragozaantigua/14834912587/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21224, 'Expo 1908', 'Imagen de una placa metâ”śĂ­lica conmemorativa de la Exposiciâ”śâ”‚n Hispano-Francesa de 1908, realizada por el escultor francâ”śÂ®s Dautel Pierre-Victor. Entre los alegâ”śâ”‚ricos motivos de la imagen, de fondo, la puerta de acceso a la Exposiciâ”śâ”‚n, situada en el antiguo paseo de la Mina, donde hoy confluyen las calles de Mariano Escar con el paseo de la Constituciâ”śâ”‚n. Fuente visual: Ministâ”śÂżre de la Culture (France) - Mâ”śÂ®diathâ”śÂżque de l''architecture et du patrimoine - diffusion RMN', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64787900, -0.88053700, '0101000020E6100000DD5F3DEE5B2DECBFF261F6B2EDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16281568145.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16281568145.webp', 'https://www.flickr.com/photos/zaragozaantigua/16281568145/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21237, 'Exposiciâ”śâ”‚n Hispano Francesa 1908', '"Exposiciâ”śâ”‚n de Zaragoza". Serie de catorce tarjetas postales que reproducen acuarelas de Fâ”śÂ®lix Lafuente con motivos de la Exposiciâ”śâ”‚n Hispano Francesa de 1908, celebrada en la Huerta de Santa Engracia. Fuente: paisajesviajados.com', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64787900, -0.88053700, '0101000020E6100000DD5F3DEE5B2DECBFF261F6B2EDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19587060776.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19587060776.webp', 'https://www.flickr.com/photos/zaragozaantigua/19587060776/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21238, 'Salida Exposiciâ”śâ”‚n Hispano Francesa 1908', 'Foto: Ignacio Coyne, 1908. "Pabellâ”śâ”‚n de Elâ”śÂ®ctricas Reunidas". En realidad, puerta de acceso a la Exposiciâ”śâ”‚n Hispano Francesa de Zaragoza, vista desde dentro del recinto. Fuente: dara.aragon.es/', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64787900, -0.88053700, '0101000020E6100000DD5F3DEE5B2DECBFF261F6B2EDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19614562941.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19614562941.webp', 'https://www.flickr.com/photos/zaragozaantigua/19614562941/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21294, 'Exposiciâ”śâ”‚n 1908', 'Imagen de la puerta de ingreso a la Exposiciâ”śâ”‚n Hispano-Francesa de 1908 capturada desde el exterior del recinto, en el terroso paseo de la Mina. Bajo el arco rebajado de entrada (en el que aparece rotulada la indicaciâ”śâ”‚n "EXPOSICIâ”śĂ´N HISPANO FRANCESA") se atisba en furioso contraste lumâ”śÂˇnico el jardâ”śÂˇn central y la fuente artâ”śÂˇstica realizada por el escultor Dionisio Lasuâ”śÂ®n y, al fondo, el Pabellâ”śâ”‚n de Alimentaciâ”śâ”‚n o pabellâ”śâ”‚n destinado a exposiciâ”śâ”‚n de productos alimenticios. En primer tâ”śÂ®rmino, un lujoso coche de caballos (posiblemente un "Victoria") con el conductor aguardando el regreso de su seâ”śâ–’or. Fuente visual: Archivo fotogrâ”śĂ­fico histâ”śâ”‚rico del SIPA, en AHPZ.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64775300, -0.88020300, '0101000020E610000031EA5A7B9F2AECBF6571FF91E9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30160461757.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30160461757.webp', 'https://www.flickr.com/photos/zaragozaantigua/30160461757/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21296, 'Expo 1908', 'Imagen de la Exposiciâ”śâ”‚n Hispano Francesa de 1908 obtenida, posiblemente, desde la circular terracilla que culminaba el Pabellâ”śâ”‚n de la Alimentaciâ”śâ”‚n, con el objetivo orientado hacia el sur, y centrado en la puerta principal de acceso a la muestra expositiva, habilitada en la antigua Huerta de Santa Engracia. A la izquierda, el pabellâ”śâ”‚n de Maquinaria, y a la derecha, el de Tracciâ”śâ”‚n, junto al que destaca, en primer plano, el pabellâ”śâ”‚n particular de la TUDOR. Tras la puerta de ingreso, el arbolado paseo de la Mina y el cauce al aire del Huerva. Al fondo, a la izquierda, la chimenea de una de las harineras ubicadas en la gran curva del râ”śÂˇo previa a las instalaciones del Gasâ”śâ”‚metro. Fuente visual: Ignacio Coyne, en www.todocoleccion.net/', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64775300, -0.88020300, '0101000020E610000031EA5A7B9F2AECBF6571FF91E9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31513921262.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31513921262.webp', 'https://www.flickr.com/photos/zaragozaantigua/31513921262/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21321, 'Exposiciâ”śâ”‚n de 1908', 'Imagen capturada en la Gran Plaza de ingreso a la Exposiciâ”śâ”‚n Hispano-Francesa de 1908 y centrada en la efâ”śÂˇmera y artâ”śÂˇstica fuente proyectada por el escultor Dionisio Lasuâ”śÂ®n en formas naturalistas y ornada con motivos simbâ”śâ”‚licos y mitolâ”śâ”‚gicos. Esta fuente estaba situada en el centro de la Gran Plaza de la muestra, entre pequeâ”śâ–’os jardines de factura inglesa realizados por la Secciâ”śâ”‚n de Jardinerâ”śÂˇa del Ayuntamiento. Al fondo, gran fachada del Pabellâ”śâ”‚n de Alimentaciâ”śâ”‚n rematado por las banderas nacionales del Reino de Espaâ”śâ–’a y de la Repâ”śâ•‘blica de Francia. Entre las naturalizadas columnas de la fuente, vista parcial de la instalaciâ”śâ”‚n del Acumulador Tudor, y de la chimenea de la central elâ”śÂ®ctrica secundaria de la Compaâ”śâ–’â”śÂˇa Aragonesa de Electricidad ubicada en la calle de San Miguel. A la izquierda, el Pabellâ”śâ”‚n de Maquinaria. Fuente visual: foto Ignacio Coyne (Archivo Coyne), en AHPZ.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64792900, -0.87996700, '0101000020E61000003BE5D18DB028ECBFA3906456EFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44242483485.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44242483485.webp', 'https://www.flickr.com/photos/zaragozaantigua/44242483485/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21322, 'Exposiciâ”śâ”‚n 1908', 'Imagen de la puerta de ingreso a la Exposiciâ”śâ”‚n Hispano-Francesa de 1908, capturada desde el interior del recinto, junto al arranque del jardâ”śÂˇn central donde fue emplazada la llamativa fuente artâ”śÂˇstica realizada por el escultor Dionisio Lasuâ”śÂ®n. Al fondo, el arbolado paseo de La Mina paralelo al cauce al aire del râ”śÂˇo Huerva. Esta puerta fue proyectada con aires modernistas por el arquitecto Ricardo Magdalena al modo de los efâ”śÂˇmeros arcos triunfales construidos para conmemorar temporalmente un evento. Fuente visual: Archivo fotogrâ”śĂ­fico histâ”śâ”‚rico del SIPA, en AHPZ.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64775300, -0.88020300, '0101000020E610000031EA5A7B9F2AECBF6571FF91E9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45022523842.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45022523842.webp', 'https://www.flickr.com/photos/zaragozaantigua/45022523842/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21433, 'P.â”¬â•‘ de los Plâ”śĂ­tanos 1911', 'Imagen capturada entre las humeantes ruinas de la fâ”śĂ­brica de camas de la viuda de Daroca sita en el paseo de los Plâ”śĂ­tanos, devastada por un incendio que se habâ”śÂˇa iniciado en el vecino taller de ebanisterâ”śÂˇa de Garcâ”śÂˇa y Valdâ”śÂ®s, se propagâ”śâ”‚ a la fâ”śĂ­brica de tintes de Cea, y llegâ”śâ”‚ hasta la referida fâ”śĂ­brica de camas, donde los bomberos e ingenieros pontoneros pudieron finalmente extinguirlo y evitar que se extendiera a la fâ”śĂ­brica de clariâ”śâ”‚n de Victoriano Casanada. Fuente visual: El fotâ”śâ”‚grafo Luis Gandâ”śâ•‘ Mercadal. Una crâ”śâ”‚nica visual 1910-1930.', 1911, 1911, 1911, 'Anos 10', 'CENTRO', 41.64702300, -0.88093200, '0101000020E6100000F4FE3F4E9830ECBF416150A6D1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37034196870.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37034196870.webp', 'https://www.flickr.com/photos/zaragozaantigua/37034196870/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21488, 'Huerva al aire 1926', 'Aspecto del Huerva fluyendo por la ciudad antes del cubrimiento. La imagen captura el puente de paso que seâ”śâ–’alaba el punto, en las traseras de la iglesia de Santa Engracia, donde arrancaba el Paseo de la Mina hacia la derecha. A la izquierda, cruzando el puente, comenzaba el Camino de los Plâ”śĂ­tanos, a la sombra del colegio de los Jesuitas.', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.64814400, -0.88273600, '0101000020E6100000340F60915F3FECBFA08CF161F6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15136358486.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15136358486.webp', 'https://www.flickr.com/photos/zaragozaantigua/15136358486/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21645, 'Plaza de Castelar c.1923', 'Imagen de la plaza de Castelar durante su etapa como estacional recinto de ferias y atracciones de la ciudad durante el verano, bajo la denominaciâ”śâ”‚n de Saturno Park. La captura se ha realizado sobre la despejada manzana sin urbanizar al sur de la prolongaciâ”śâ”‚n de la calle de Joaquâ”śÂˇn Costa, donde pocos aâ”śâ–’os despuâ”śÂ®s se barajarâ”śÂˇa la posibilidad de construir el nuevo edificio del ayuntamiento. Al fondo, el arbolado paseo de la Mina y chimeneas emergentes del otro lado del râ”śÂˇo Huerva.', 1923, 1923, 1923, 'Anos 20', 'CENTRO', 41.64801500, -0.88012900, '0101000020E61000009F5BE84A042AECBFA228D027F2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51250000040.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51250000040.webp', 'https://www.flickr.com/photos/zaragozaantigua/51250000040/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21777, 'Plaza Castelar 1934', 'Solar sin construir de la Plaza de Castelar, en el que estaba previsto construir el nuevo edificio del Ayuntamiento. Al fondo, el edificio del Museo Provincial. A la derecha, continuaciâ”śâ”‚n de la calle de Costa. Fuente visual: Foto Conrado Barlâ”śÂ®s, donada por Daniel Barlâ”śÂ®s y digitalizada por Josâ”śÂ® Luis Cintora para www.rafaelcastillejo.com', 1934, 1934, 1934, 'Anos 30', 'CENTRO', 41.64817400, -0.87986200, '0101000020E6100000E7C75F5AD427ECBF0A0F9A5DF7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22950781010.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22950781010.webp', 'https://www.flickr.com/photos/zaragozaantigua/22950781010/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21812, 'Av. Galâ”śĂ­n y Garcâ”śÂˇa Hernâ”śĂ­ndez 1933', '"Urbanizaciâ”śâ”‚n de la Gran Vâ”śÂˇa sobre el cubrimiento del râ”śÂˇo Huerva (secciâ”śâ”‚n 2â”¬Â¬)", Miguel â”śĂĽngel Navarro, mayo de 1933. Plano del proyecto de urbanizaciâ”śâ”‚n del cubrimiento del râ”śÂˇo Huerva en el tramo de la "Gran Vâ”śÂˇa" luego llamado avenida de Galâ”śĂ­n y Garcâ”śÂˇa Hernâ”śĂ­ndez, denominaciâ”śâ”‚n sustituida en el franquismo por la de Marina Moreno. En rojo, las manzanas que habrâ”śĂ­n de construirse en el entorno del antiguo paseo de los Plâ”śĂ­tanos. Fuente visual: Archivo Municipal de Zaragoza.', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.64816900, -0.88255800, '0101000020E610000064575A46EA3DECBFF9A3A833F7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30485451106.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30485451106.webp', 'https://www.flickr.com/photos/zaragozaantigua/30485451106/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21914, 'C.â”¬â•‘ de las Torres c.1935', 'Inâ”śÂ®dita imagen centrada en las instalaciones de la Industria Lanera S.A. localizada en el nâ”śâ•‘mero 121 del camino de las Torres. En primer tâ”śÂ®rmino, la huerta del gran recinto del convento-colegio de los PP. Agustinos, desde donde se ha tomado la fotografâ”śÂˇa. Esta fâ”śĂ­brica y la huerta se abastecâ”śÂˇan del agua proporcionada por la acequia de las Adulas o de San Josâ”śÂ® que fluâ”śÂˇa al aire en paralelo por el camino de las Torres (leve vista de este camino a la izquierda). Tras la fâ”śĂ­brica, edificio que esquinaba la desembocadura del paseo de Sasera (actual paseo de las Damas) donde destaca una vista parcial del antiguo convento-noviciado de la Congregaciâ”śâ”‚n de las Hermanas Oblatas del Santâ”śÂˇsimo Redentor. En el centro y al fondo se perfilan algunas torres de las iglesias y las dos catedrales del centro de la ciudad.', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.64272400, -0.88169500, '0101000020E6100000BB7EC16ED836ECBF5A2DB0C744D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53198982460.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53198982460.webp', 'https://www.flickr.com/photos/zaragozaantigua/53198982460/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21995, 'Av. Marina Moreno 1941', 'Bajo una intensa solanera, y mientras la Uniâ”śâ”‚n Soviâ”śÂ®tica estaba siendo invadida por la Alemania nazi, la 10â”¬Â¬ etapa de la IIIâ”¬Â¬ Vuelta Ciclista a Espaâ”śâ–’a, con salida en Barcelona, llegâ”śâ”‚ a la lâ”śÂˇnea de meta establecida en Zaragoza. En la imagen, en la avenida de Marina Moreno, el vencedor de la etapa, Delio Rodrâ”śÂˇguez (a la izquierda), tras casi 11 apalizantes horas y cuarto al pedal, junto a otros destacados corredores, como Fermâ”śÂˇn Trueba "el Mini", lâ”śÂˇder provisional de la clasificaciâ”śâ”‚n general. En la tribuna del fondo, para autoridades y jerarquâ”śÂˇas locales, entusiastas seâ”śâ–’oritas de la Secciâ”śâ”‚n Femenina de Falange posan con sus impecables camisas azules, tras su desempeâ”śâ–’o en la ofrenda floral a los velocipedistas. Organizâ”śâ”‚ el evento la Obra Sindical Educaciâ”śâ”‚n y Descanso. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1941, 1941, 1941, 'Anos 40', 'CENTRO', 41.64809200, -0.88222300, '0101000020E6100000A2ED98BA2B3BECBF4D66BCADF4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32082434553.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32082434553.webp', 'https://www.flickr.com/photos/zaragozaantigua/32082434553/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22107, 'Convento Oblatas c.1957', 'En 1865 comenzâ”śâ”‚ sus andanzas mundanales la "Congregaciâ”śâ”‚n de las Hermanas Oblatas del Santâ”śÂˇsimo Redentor", que llegaron a la ciudad unos aâ”śâ–’os despuâ”śÂ®s, y en 1887 fundaron su convento-noviciado en los terrenos de la hasta entonces "Torre de Ponte", al final de un antiguo camino que entonces empezaba a ser conocido como "Paseo de las Damas". Allâ”śÂˇ se levantâ”śâ”‚ un conjunto conventual destacable, con sus huertos y campos de cultivo, con una capilla provisional y un asilo para "desamparadas". En 1909 inauguraron allâ”śÂˇ unos locales para enfermerâ”śÂˇa, y en 1910 abrieron un nuevo edificio para el noviciado y una nueva capilla. Desde 1939 ejerciâ”śâ”‚ de "asilo" de mujeres que eran allâ”śÂˇ recluidas a la espera de juicio por no apoyar el golpe militar de julio de 1936. A finales de los aâ”śâ–’os 40, su estado de ruina llevâ”śâ”‚ a la Congregaciâ”śâ”‚n a construir un nuevo noviciado en Pamplona. El presente edificio fue derribado y, tras vender algo mâ”śĂ­s de la mitad del original terreno, fue construido uno nuevo a comienzos de la prodigiosa dâ”śÂ®cada de los 60, ahora como una estructura achaflanada con el Camino de las Torres, que a su vez tambiâ”śÂ®n fue derribada tras venderla a buen postor, y no alcanzâ”śâ”‚ a ver el no menos atractivo siglo XXI. En la imagen, el convento-noviciado capturado desde la atalaya de la torre capuchino-italiana de San Antonio. El color amarillo es un aâ”śâ–’adido no original. Justo a la izquierda de la iglesia conventual, el actual nâ”¬â•‘ 27 de la calle de la Paz. Delante, las curiosas edificaciones de la calle Vista Alegre, restos del "Barrio de los Chiflaos", que parecen tener continuidad en el colegio-convento de los PP. Agustinos. A su derecha, la chimenea de la fâ”śĂ­brica textil "Lanera Aragonesa". Fuente visual: "Los tranvâ”śÂˇas de Zaragoza", J. Peâ”śâ–’a-J.M. Valero, 1985, DPZ.', 1957, 1957, 1957, 'Anos 50', 'CENTRO', 41.64357400, -0.88263900, '0101000020E61000009692E524943EECBF284701A260D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21442159240.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21442159240.webp', 'https://www.flickr.com/photos/zaragozaantigua/21442159240/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22129, 'Av. Marina Moreno 1951', 'Imagen de la avenida de Marina Moreno a la altura de la nueva calle de San Ignacio de Loyola, en torno a la cual se estaba produciendo, poco a poco, la urbanizaciâ”śâ”‚n de la antigua zona residencial y fabril del paseo de los Plâ”śĂ­tanos (tras los edificios). Unos pocos aâ”śâ–’os antes habâ”śÂˇa sido inaugurado el edificio pionero de la nueva sede de la Delegaciâ”śâ”‚n Provincial de Sindicatos (centro de la imagen). Al fondo, a la izquierda, el antiguo edificio del colegio del Sagrado Corazâ”śâ”‚n, en el paseo de la Mina, en cuyas inmediaciones finalizaba el cubrimiento del râ”śÂˇo Huerva. Fuente visual: Archivo Construcciones y Auxiliar de Ferrocarriles (DARA-AHPZ)', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.64781500, -0.88258600, '0101000020E6100000E109BDFE243EECBFDB6D179AEBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23353348304.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23353348304.webp', 'https://www.flickr.com/photos/zaragozaantigua/23353348304/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22142, 'P.â”¬â•‘ de Marina Moreno c.1955', 'Vista nocturna del paseo de Marina Moreno, con la plaza de Basilio Paraâ”śÂˇso al fondo. A la izquierda, chaflâ”śĂ­n de la Residencia Universitaria de los PP. Jesuitas, como parte de su gran complejo de formaciâ”śâ”‚n. A la derecha, luminoso chaflancillo del antiguo antiguo Hotel Regina, Hotel Centenario en el momento de la captura fotogrâ”śĂ­fica, en la calle de Juan Bruil. Fuente visual: zaragozabuenasnoticias.com/', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64783600, -0.88397200, '0101000020E6100000008DD2A57F49ECBFF295404AECD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25087622531.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25087622531.webp', 'https://www.flickr.com/photos/zaragozaantigua/25087622531/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22260, 'Marina Moreno 1968', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. 25/11/1968. Vista desde el Paseo de Marina Moreno de las traseras de los hotelitos de la Plaza de Aragâ”śâ”‚n, un poco antes de que alguien ideara una alternativa mâ”śĂ­s atractiva econâ”śâ”‚micamente que ser mero soporte de vallas publicitarias: piquetearlos y construir nuevos y enormes bloques de viviendas y oficinas. La callecita por la que se mete un 600 es Agustina Simâ”śâ”‚n.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.64798300, -0.88319200, '0101000020E6100000B6D782DE1B43ECBF97AE601BF1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14762647828.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14762647828.webp', 'https://www.flickr.com/photos/zaragozaantigua/14762647828/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22266, 'Cine Parâ”śÂˇs 1968', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/diciembre 1968. Inaugurado en 1957, el Cine Parâ”śÂˇs estaba ubicado en el Paseo de las Damas nâ”¬â•‘ 11, anterior y terroso "Paseo de Sasera", que escoltado entre el colegio y el convento de los jesuâ”śÂˇtas, conducâ”śÂˇa desde la Plaza Paraâ”śÂˇso hacia el rural Camino de las Torres. Este cine era ya de un tamaâ”śâ–’o considerable, con 750 butacas, orientado inicialmente a pelâ”śÂˇculas familiares y toleradas para menores. Cerrâ”śâ”‚ en enero de 1984. En la imagen, salida de una sesiâ”śâ”‚n de cine en versiâ”śâ”‚n original de la pelâ”śÂˇcula espaâ”śâ–’ola "Las cicatrices", sobre toreros, y protagonizada por el Alfredo Landa de los 60-70. El cine de toreros tambiâ”śÂ®n era considerado como cine para pâ”śâ•‘blico infantil, porque parece que al seâ”śâ–’or del sombrero no le ha terminado de entretener lo suficiente.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.64565800, -0.88458100, '0101000020E6100000193735D07C4EECBF4C33DDEBA4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14850665475.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14850665475.webp', 'https://www.flickr.com/photos/zaragozaantigua/14850665475/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22312, 'Calle de Bruil 1966', 'Tras la Exposiciâ”śâ”‚n Aragonesa de 1868, los terrenos de la Glorieta de Pignatelli, cerca del Huerva, se parcelaron y comenzaron a urbanizarse. La denominada "Manzana D" quedâ”śâ”‚ delimitada por la Glorieta, la nueva calle Bruil, el râ”śÂˇo Huerva, y la nueva calle Puigcerdâ”śĂ­. En el solar nâ”¬â•‘ 1 de la manzana se edificâ”śâ”‚ el hotelito de la familia Baylâ”śÂˇn (1887), que pronto pasâ”śâ”‚ a manos de Tomâ”śĂ­s Castellano (1890). Con motivo de la Expo de 1908, se levantâ”śâ”‚ al lado un inmueble con idea de explotarlo como hotel durante la muestra. Al nuevo edificio se le dio el nombre de "Gran Hotel Regina", tenâ”śÂˇa entrada por la calle Bruil, y era considerado el primer hotel de traza moderna de la ciudad. Tras la Expo, el hotelito de la plaza fue alquilado para sede del Gobierno Civil (1911), y el Hotel fue colegio de los Hermanos del Sagrado Corazâ”śâ”‚n (1913-1919). De 1919 a 1939 aquâ”śÂˇ se instalâ”śâ”‚ una Academia Preparatoria Militar que entre 1936-39 fue reconvertida en centro de represiâ”śâ”‚n contra republicanos. Recuperâ”śâ”‚ su original funciâ”śâ”‚n (Hotel) durante los festejos del XIX Centenario de la Venida de la Virgen del Pilar (en carne mortal) a Zaragoza. Fue reformado segâ”śâ•‘n proyecto de Teodoro Râ”śÂˇos, y se le denominâ”śâ”‚ "Hotel Centenario", que en 1942 fue nuevamente reformado. En 1966 una inmobiliaria-constructora lo derribâ”śâ”‚, y levantâ”śâ”‚ sobre su solar en macizada verticalidad un nuevo Hotel, viviendas, y locales comerciales. Hacia la plaza de Aragâ”śâ”‚n, el antiguo Gobierno Civil era piqueteado sincronizadamente. En la imagen, chaflâ”śĂ­n entre la calle Bruil (derecha) y Marina Moreno (izquierda), con visual del antiguo Hotel Regina-Hotel Centenario de la calle Bruil. A continuaciâ”śâ”‚n, los jardines del antiguo Gobierno Civil. Al fondo, pasando el Paseo de la Independencia, el correspondiente hotelito esquinado con la calle Albareda (piqueteado en 1977). Fuente visual: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.64824000, -0.88314400, '0101000020E61000007313B534B742ECBFC2FA3F87F9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15735355718.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15735355718.webp', 'https://www.flickr.com/photos/zaragozaantigua/15735355718/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22362, 'P.â”¬â•‘ de las Damas 1969', 'Foto: Colecciâ”śâ”‚n Josâ”śÂ® Ignacio Lorenzo. 15 de mayo de 1969. Comitiva familiar procedente de una comuniâ”śâ”‚n celebrada en el convento de las Oblatas, caminando direcciâ”śâ”‚n plaza de Paraâ”śÂˇso, a la altura del nâ”śâ•‘mero 38 (izquierda) del paseo de las Damas. Fuente: www.facebook.com/photo.php?fbid=1027709830613781&set=...', 1969, 1969, 1969, 'Anos 60', 'CENTRO', 41.64366100, -0.88290900, '0101000020E610000093020B60CA40ECBFF75AD07B63D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21060922748.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21060922748.webp', 'https://www.flickr.com/photos/zaragozaantigua/21060922748/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22416, 'C.â”¬â•‘ de las Torres 1969', 'Imagen del histâ”śâ”‚rico camino de las Torres, con los bloques de viviendas recayentes a las calles de Pedro Marâ”śÂˇa Ric, General Sueiro, y Madre Vedruna, a la izquierda. A la derecha, restos de tradicionales edificaciones de la periferia de la ciudad, junto a la textil fâ”śĂ­brica "Lanera Aragonesa", cuya destacada chimenea queda fuera de campo. El cauce al aire de la acequia de las Adulas, o de San Josâ”śÂ®, se curvaba hacia la derecha en este punto para dar riego a los campos de esa parte de Miraflores. Esta vital acequia fue el origen del camino, como antigua vâ”śÂˇa de comunicaciâ”śâ”‚n con Cuarte. Las mutaciones posteriores de la zona han sido remarcables, hasta el punto de convertir este camino en una moderna trinchera, o autovâ”śÂˇa, para trâ”śĂ­fico rodado. Fuente visual: Gerardo Sancho Ramo, Archivo Municipal Zaragoza. Referencia: ES. 50297. AM 04.01.02.13 Sobre 118208', 1969, 1969, 1969, 'Anos 60', 'CENTRO', 41.64309500, -0.88111500, '0101000020E6100000357BA0151832ECBF4E9CDCEF50D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25802294063.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25802294063.webp', 'https://www.flickr.com/photos/zaragozaantigua/25802294063/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25636, 'Calle de Jerusalâ”śÂ®n 1973', 'Imagen capturada desde el estadio municipal de La Romareda y centrada en algunos de los recientes bloques que configuraban el Polâ”śÂˇgono Romareda, originalmente de la Gran Vâ”śÂˇa. Centra la escena el bloque del nâ”¬â•‘ 4 de la calle de Juan II de Aragâ”śâ”‚n, cuya sombra se proyecta junto a la del nâ”¬â•‘ 6, a la izquierda y fuera de plano. De derecha a izquierda, los bloques de los nâ”śâ•‘meros 15, 17, 21 y 23 de la calle de Asâ”śÂˇn y Palacios. Aâ”śâ–’os despuâ”śÂ®s, entre estos bloques de la imagen se construirâ”śĂ­ el moderno colegio pâ”śâ•‘blico, actual CEIP, Eliseo Godoy. En primer tâ”śÂ®rmino y a la izquierda, un vehâ”śÂˇculo aparece estacionado en la solera de la calle de Jerusalâ”śÂ®n.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.63614900, -0.90421500, '0101000020E61000003AAFB14B54EFECBF0A3197546DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47929781208.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47929781208.webp', 'https://www.flickr.com/photos/zaragozaantigua/47929781208/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22437, 'Marina Moreno 1968', 'Era conocida como la "seâ”śâ–’ora del doctor Barnard", y su nombre era Aletta Gertruida Louw, enfermera de profesiâ”śâ”‚n. En 1948 casâ”śâ”‚ con Christiaan Neethling Barnard, que como mâ”śÂ®dico cirujano realizâ”śâ”‚ en 1967 el primer transplante de corazâ”śâ”‚n en un humano, lo que le convirtiâ”śâ”‚ en un fenâ”śâ”‚meno mediâ”śĂ­tico. Tras ser portada en la revista Time, el "Dr. Barnard" ascendiâ”śâ”‚ a la talla de personaje internacional, con autâ”śÂ®nticas "giras" mundiales y entrevistas en las TV de muchos paâ”śÂˇses, y fue equiparado a las grandes estrellas del cine, la mâ”śâ•‘sica, y la cultura de masas. Durante su paso por Zaragoza en una de esas giras mundiales, la "Sra. Barnard" ejerciâ”śâ”‚ de devota esposa del famoso doctor, escenificando las funciones que la sociedad patriarcal ha impuesto como propias de su sexo, como ir de compras. En la imagen, Aletta sale sonriente y cargada de gâ”śÂ®neros de la tienda de decoraciâ”śâ”‚n y jugueterâ”śÂˇa denominada "Children''s", en el paseo de Marina Moreno. Un par de aâ”śâ–’os despuâ”śÂ®s, Aletta y Christiaan firmaron el divorcio. Fuente visual: Fernando Sancho Ramo, AMZ.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.64755200, -0.88134000, '0101000020E6100000320395F1EF33ECBFCD3AE3FBE2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30580559545.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30580559545.webp', 'https://www.flickr.com/photos/zaragozaantigua/30580559545/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22470, 'Camino de las Torres 1969', 'Imagen del camino de las Torres en el comienzo de su mutaciâ”śâ”‚n a avenida, o vâ”śÂˇa râ”śĂ­pida para trâ”śĂ­fico rodado. La anchura original habâ”śÂˇa aguantado varios siglos, pero parece ser que ya no compaginaba con la modernidad requerida, ni con el debido embellecimiento de un entorno edilicio hasta hacâ”śÂˇa poco prâ”śĂ­cticamente inexistente. La captura se ha realizado casi en la esquina con la calle del General Sueiro (a la espalda del fotâ”śâ”‚grafo). A la izquierda, restos de parcelas anexas a la textil fâ”śĂ­brica "Lanera Aragonesa", con su referente y destacada chimenea. Al fondo, nuevos bloques de la reciente plaza de Albert Schweitzer. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1969, 1969, 1969, 'Anos 60', 'CENTRO', 41.64325500, -0.88088900, '0101000020E610000022FFCC203E30ECBF87FE092E56D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33231150311.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33231150311.webp', 'https://www.flickr.com/photos/zaragozaantigua/33231150311/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22598, 'Residencia PP Jesuitas 1976', 'El arquitecto Josâ”śÂ® Romero, junto a su hermano Manuel, firman en 1952 el proyecto de Residencia Universitaria de los PP. Jesuitas en Zaragoza, integrado en la enorme manzana del colegio de la misma orden, y chaflaneando entre la avenida de Marina Moreno y la reciente calle denominada "Arquitecto Yarza". Esta Residencia fue ideada para dar servicio a los antiguos alumnos del Colegio de El Salvador, y de otros colegios situados en localidades sin universidad. Es levantado en cuatro plantas, mâ”śĂ­s unos locales comerciales de alquiler, en formas racionalistas. El chaflâ”śĂ­n articula las dos alas del edificio, y el material fundamental es el ladrillo, reservando la piedra para la planta baja y el chaflâ”śĂ­n, culminado con un altorrelieve como â”śâ•‘nica concesiâ”śâ”‚n ornamental. En la imagen, vista de la Residencia desde Marina Moreno. A la izquierda, la calle Arquitecto Yarza. Tiempo despuâ”śÂ®s, este edificio perdiâ”śâ”‚ su funciâ”śâ”‚n original, y fue muy transformado, tanto en funciones, formas, como en tamaâ”śâ–’o, ganando entre una y tres alturas extra. Conserva los bajos comerciales, aunque sin misiones en tierra de indios. Fuente: Archivo Pâ”śâ•‘blico Municipal, Gerardo Sancho Ramo..', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.64754200, -0.88374400, '0101000020E6100000BF28417FA147ECBFAA6400A8E2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18567831093.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18567831093.webp', 'https://www.flickr.com/photos/zaragozaantigua/18567831093/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22649, 'Marcelino Camacho 1979', 'La Organizaciâ”śâ”‚n Sindical Espaâ”śâ–’ola, o "Sindicato Vertical", fue la â”śâ•‘nica central tolerada en toda Espaâ”śâ–’a entre 1940 y 1976, aunque ya desde 1936 el nuevo râ”śÂ®gimen franquista iba aniquilando los sindicatos de clase conforme avanzaba militarmente para recuperar la hegemonâ”śÂˇa de la Espaâ”śâ–’a profunda. El 1â”¬â•‘ de abril de 1977, tras la legalizaciâ”śâ”‚n de algunos partidos polâ”śÂˇticos, fue reconocido el derecho de asociaciâ”śâ”‚n sindical, y las Comisiones Obreras, la protagâ”śâ”‚nica organizaciâ”śâ”‚n de trabajadores y trabajadoras, dejaron de ser clandestinas. Marcelino Camacho fue uno de sus principales impulsores y referentes, y desde 1976 era su Secretario General. En las elecciones constituyentes de 1977 fue elegido diputado por Madrid en la lista del PCE, siendo reelegido en las elecciones generales de 1979. Dimitirâ”śĂ­ en 1981 como diputado por desacuerdo con el trabajo institucional del PCE, y continuarâ”śĂ­ como Secretario General de CCOO hasta 1987, protagonizando intensas movilizaciones contra la polâ”śÂˇtica econâ”śâ”‚mica de los primeros gobiernos socialistas. En la imagen, Marcelino Camacho en el salâ”śâ”‚n de actos del original edificio de la "Casa Sindical", inaugurada en 1945 en el Paseo de Marina Moreno, y que tras la disoluciâ”śâ”‚n del mismo fue cedido a CCOO, manteniendo el Estado Central su titularidad. Fuente visual: Archivo Pâ”śâ•‘blico Municipal, Gerardo Sancho Ramo.', 1979, 1979, 1979, 'Anos 70', 'CENTRO', 41.64781500, -0.88258600, '0101000020E6100000E109BDFE243EECBFDB6D179AEBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20999869744.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20999869744.webp', 'https://www.flickr.com/photos/zaragozaantigua/20999869744/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
